class Solution {
    public int minChanges(int[] nums, int k) {
        int maxVal = 1 << 10;
        int[][] count = new int[k][maxVal];
        int[] totalCount = new int[k];

        for (int i = 0; i < nums.length; i++) {
            count[i % k][nums[i]]++;
            totalCount[i % k]++;
        }

        int[][] dp = new int[k][maxVal];
        for (int i = 0; i < maxVal; i++) {
            dp[k - 1][i] = totalCount[k - 1] - count[k - 1][i];
        }

        for (int i = k - 2; i >= 0; i--) {
            int[] nextDp = dp[i + 1];
            int minNextDp = Integer.MAX_VALUE;
            for (int val : nextDp) {
                minNextDp = Math.min(minNextDp, val);
            }

            for (int j = 0; j < maxVal; j++) {
                int curCount = totalCount[i];
                dp[i][j] = curCount - count[i][j] + minNextDp;
                for (int prevXor = 0; prevXor < maxVal; prevXor++) {
                    int nextXor = prevXor ^ j;
                    dp[i][prevXor] = Math.min(dp[i][prevXor], curCount - count[i][j] + nextDp[nextXor]);
                }
            }
        }

        return dp[0][0];
    }
}
